import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Page } from '../components/Layout';
import { loginUser, saveToken } from '../services/authService';

export default function LoginPage() {
  const navigate = useNavigate();
  const [role, setRole] = useState('CUSTOMER');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (event) => {
    event.preventDefault();
    setError('');
    setLoading(true);

    try {
      const data = await loginUser({ email, password, role });

      if (!data.success) {
        setError(data.message || 'Login failed');
        setLoading(false);
        return;
      }

      saveToken(data.token, data.role, data.name, data.id, data.email, {
        firstname: data.firstname,
        lastname: data.lastname,
        contact: data.contact,
        address: data.address,
        licenseNumber: data.licenseNumber,
        licenseExpiry: data.licenseExpiry
      });

      navigate(data.role === 'ADMIN' ? '/admin/bookings' : '/customer/bookings');
    } catch (err) {
      setError(err?.response?.data?.message || 'Login failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Page title="Welcome Back" subtitle="Login as customer or admin to continue with bookings and approvals.">
      <section className="authShell">
        <div className="authShowcase">
          <div className="authBadge">Car Rental System</div>
          <h2>Fast access to customer bookings and admin approvals.</h2>
          <p>
            Customers can track requests and profiles. Admins can review pending bookings and approve them from the panel.
          </p>
        </div>
        <form className="card formCard authCard" onSubmit={handleSubmit}>
          {error && <div className="alert error">{error}</div>}
          <label>
            Role
            <select value={role} onChange={(e) => setRole(e.target.value)}>
              <option value="CUSTOMER">Customer</option>
              <option value="ADMIN">Admin</option>
            </select>
          </label>
          <label>
            Email
            <input value={email} onChange={(e) => setEmail(e.target.value)} type="email" placeholder="Enter email" />
          </label>
          <label>
            Password
            <input value={password} onChange={(e) => setPassword(e.target.value)} type="password" placeholder="Enter password" />
          </label>
          <button className="button" disabled={loading} type="submit">
            {loading ? 'Logging in...' : 'Login'}
          </button>
        </form>
      </section>
    </Page>
  );
}
